export const generateBranding = async (profile: BrandProfile): Promise<BrandingResult> => {
  const ai = getAI();
  const prompt = `
    Génère une identité de marque EXCLUSIVE pour "${profile.companyName}".
    Secteur : ${profile.industry}
    Positionnement : ${profile.positioning}

    Inclus dans le JSON :
    - uniquenessFactor : Pourquoi ce logo est structurellement unique ?
    - differentiationStrategy : Stratégie visuelle.
    - svgPath : CHAÎNE DE CARACTÈRES 'D' (viewBox 0 0 512 512).
    - Des spécifications pour les cartes de visite et flyers incluant la disposition.

    Réponds en JSON uniquement.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: BRANDING_SCHEMA,
    },
  });

  return JSON.parse(response.text.trim());
};

export const generateBrandingFromLogo = async (logoBase64: string, companyName: string): Promise<BrandingResult> => {
  const ai = getAI();
  const cleanBase64 = logoBase64.replace(/^data:image\/\w+;base64,/, "");

  const prompt = `
    Analyse visuellement ce logo pour la marque "${companyName}".
    Extrais les couleurs exactes (HEX), le style typographique, l'ambiance visuelle et l'intention de design.
    Sur la base de cette analyse, génère une charte graphique complète, cohérente et premium.

    Inclus dans le JSON :
    - uniquenessFactor : Analyse de la structure visuelle actuelle.
    - differentiationStrategy : Comment renforcer l'identité existante.
    - svgPath : Tente de recréer un tracé simplifié du symbole principal (chaîne 'D').

    Réponds en JSON uniquement.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: [
      { text: prompt },
      { inlineData: { mimeType: 'image/png', data: cleanBase64 } }
    ],
    config: {
      systemInstruction: SYSTEM_INSTRUCTION,
      responseMimeType: "application/json",
      responseSchema: BRANDING_SCHEMA,
    },
  });

  return JSON.parse(response.text.trim());
};

export const generateImagePro = async (prompt: string, aspectRatio: any = "1:1"): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-image-preview',
    contents: { parts: [{ text: `High-end professional UNIQUE brand asset. Minimalist, premium, iconic. Prompt: ${prompt}` }] },
    config: { imageConfig: { aspectRatio: aspectRatio, imageSize: "1K" } }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Erreur de génération d'image Pro.");
};

export const generateImage = async (prompt: string, base64ReferenceImage?: string): Promise<string> => {
  const ai = getAI();
  const parts: any[] = [{ text: `High-end professional UNIQUE and UNMISTAKABLE branding asset. Pure white background. Minimalist. Prompt: ${prompt}` }];
  if (base64ReferenceImage) {
    const cleanBase64 = base64ReferenceImage.replace(/^data:image\/\w+;base64,/, "");
    parts.unshift({
      inlineData: { mimeType: 'image/png', data: cleanBase64 },
    });
  }
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: { parts: parts },
    config: { imageConfig: { aspectRatio: "1:1" } }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Erreur de génération d'image.");
};

export const editImageWithPrompt = async (base64Image: string, prompt: string): Promise<string> => {
  const ai = getAI();
  const cleanBase64 = base64Image.replace(/^data:image\/\w+;base64,/, "");
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-image',
    contents: {
      parts: [
        { inlineData: { data: cleanBase64, mimeType: 'image/png' } },
        { text: prompt }
      ]
    }
  });
  for (const part of response.candidates?.[0]?.content?.parts || []) {
    if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
  }
  throw new Error("Erreur lors de l'édition de l'image.");
};

export const generateVideoVeo = async (base64Image: string, prompt: string, isLandscape: boolean = true): Promise<string> => {
  const ai = getAI();
  const cleanBase64 = base64Image.replace(/^data:image\/\w+;base64,/, "");

  let operation = await ai.models.generateVideos({
    model: 'veo-3.1-fast-generate-preview',
    prompt: prompt,
    image: {
      imageBytes: cleanBase64,
      mimeType: 'image/png',
    },
    config: {
      numberOfVideos: 1,
      resolution: '720p',
      aspectRatio: isLandscape ? '16:9' : '9:16'
    }
  });

  while (!operation.done) {
    await new Promise(resolve => setTimeout(resolve, 10000));
    operation = await ai.operations.getVideosOperation({ operation: operation });
  }

  const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
  const videoResponse = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
  const videoBlob = await videoResponse.blob();
  return URL.createObjectURL(videoBlob);
};

export const startStrategyChat = async (message: string, history: any[] = []) => {
  const ai = getAI();
  const chat = ai.chats.create({
    model: 'gemini-3-pro-preview',
    config: {
      systemInstruction: 'Tu es un expert en branding senior et consultant en stratégie de marque. Réponds de manière concise, professionnelle et inspirante.',
    },
  });
  const response = await chat.sendMessage({ message });
  return response.text;
};

export const fastAnalyzeContent = async (text: string): Promise<string> => {
  const ai = getAI();
  const response = await ai.models.generateContent({
    model: 'gemini-2.5-flash-lite-latest',
    contents: `Analyse rapidement ce contenu pour en extraire l'essence stratégique en 3 points clés : ${text}`,
  });
  return response.text || "Aucune analyse disponible.";
};

export const generateBrandLaunchPost = async (companyName: string, industry: string, visualStyle: string): Promise<string> => {
  const ai = getAI();
  const prompt = `
    Rédige un post LinkedIn de lancement officiel pour la marque "${companyName}".
    Secteur: ${industry}.
    Ton: ${visualStyle} (ex: Luxe, Tech, Minimaliste).

    Structure:
    1. Une accroche percutante.
    2. Une révélation de la nouvelle identité (pourquoi ce changement/création).
    3. Un appel à l'action subtil.

    Utilise des emojis pertinents mais avec parcimonie (style professionnel).
  `;
  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: prompt,
  });
  return response.text || "Erreur de génération du texte.";
};

import React, { useRef, useState } from 'react';
import { BrandingResult as BrandingType } from '../types';
import { generateImage, generateBrandLaunchPost } from '../services/geminiService';
// @ts-ignore
import JSZip from 'jszip';

interface BrandingResultProps {
  data: BrandingType;
  onUpdateMockups?: (mockups: string[]) => void;
  companyName: string;
}

type SectionKey = 'cover' | 'blueprint' | 'usage' | 'typography' | 'print' | 'ecosystem' | 'palette';

const BrandingResult: React.FC<BrandingResultProps> = ({ data, onUpdateMockups, companyName }) => {
  const contentRef = useRef<HTMLDivElement>(null);
  const [selectedSections, setSelectedSections] = useState<SectionKey[]>(['cover', 'blueprint', 'usage', 'typography', 'print', 'ecosystem', 'palette']);
  const [isZipping, setIsZipping] = useState(false);
  const [launchPost, setLaunchPost] = useState<string | null>(null);
  const [isGeneratingPost, setIsGeneratingPost] = useState(false);

  const getCleanPath = (rawPath: string | undefined): string => {
    if (!rawPath) return "";
    if (rawPath.includes('d="')) {
      const match = rawPath.match(/d="([^"]+)"/);
      return match ? match[1] : "";
    }
    return rawPath.replace(/<[^>]*>/g, '').trim();
  };

  const cleanSvgPath = getCleanPath(data.logo.svgPath);

  const toggleSection = (section: SectionKey) => {
    setSelectedSections(prev => 
      prev.includes(section) ? prev.filter(s => s !== section) : [...prev, section]
    );
  };

  const createSVGFile = (): Blob => {
     const svgHeader = `<?xml version="1.0" encoding="UTF-8" standalone="no"?>
<svg width="512px" height="512px" viewBox="0 0 512 512" version="1.1" xmlns="http://www.w3.org/2000/svg" xmlns:xlink="http://www.w3.org/1999/xlink">
    <title>${companyName} Master Logo Vector</title>
    <g stroke="none" stroke-width="1" fill="none" fill-rule="evenodd">
        <path d="${cleanSvgPath}" id="Logo-Path" fill="${data.styleGuide.colors[0].hex}"></path>
    </g>
</svg>`;
    return new Blob([svgHeader], { type: 'image/svg+xml' });
  };

  const handleDownloadSVGSource = () => {
    if (!cleanSvgPath) return;
    const blob = createSVGFile();
    const url = URL.createObjectURL(blob);
    const link = document.createElement('a');
    link.href = url;
    link.download = `${companyName.replace(/\s+/g, '_')}_MASTER_SOURCE.svg`;
    link.click();
    URL.revokeObjectURL(url);
  };

  const handleGenerateLaunchPost = async () => {
    setIsGeneratingPost(true);
    try {
      const post = await generateBrandLaunchPost(
        companyName, 
        "Innovation", 
        data.styleGuide.visualStyle
      );
      setLaunchPost(post);
    } catch (e) {
      console.error(e);
    } finally {
      setIsGeneratingPost(false);
    }
  };

  const handleDownloadAssets = async () => {
    setIsZipping(true);
    const zip = new JSZip();

    // 1. Identity Folder
    const identity = zip.folder("01_Identity");

    // Add SVG
    if (cleanSvgPath) {
        identity.file(`${companyName.replace(/\s+/g, '_')}_Vector.svg`, createSVGFile());
    }

    // Helper to add base64 images
    const addImg = (folder: any, name: string, dataUrl?: string) => {
        if (dataUrl) {
            const base64Data = dataUrl.replace(/^data:image\/\w+;base64,/, "");
            folder.file(name, base64Data, { base64: true });
        }
    };

    addImg(identity, "logo_master.png", data.logo.generatedImageUrl);
    addImg(identity, "logo_monochrome.png", data.logo.monochromeImageUrl);
    addImg(identity, "logo_inverted.png", data.logo.invertedImageUrl);
    addImg(identity, "favicon.png", data.logo.faviconImageUrl);

    // 2. Mockups Folder
    const mockups = zip.folder("02_Mockups");
    addImg(mockups, "business_card.png", data.styleGuide.ecosystem.print.businessCardImageUrl);
    addImg(mockups, "flyer.png", data.styleGuide.ecosystem.print.flyerImageUrl);
    addImg(mockups, "stationery_set.png", data.styleGuide.mockupImageUrl);

    data.styleGuide.extraMockups?.forEach((m, i) => {
        addImg(mockups, `context_mockup_${i+1}.png`, m);
    });

    // 3. Elements
    const elements = zip.folder("03_Elements");
    addImg(elements, "brand_pattern.png", data.styleGuide.graphicElements.patternImageUrl);

    try {
        const content = await zip.generateAsync({ type: "blob" });
        const url = URL.createObjectURL(content);
        const link = document.createElement('a');
        link.href = url;
        link.download = `${companyName.replace(/\s+/g, '_')}_BRAND_ASSETS_PACK.zip`;
        link.click();
        URL.revokeObjectURL(url);
    } catch (e) {
        console.error("Zip error", e);
    } finally {
        setIsZipping(false);
    }
  };

  const handleDownloadPDF = async () => {
    if (!contentRef.current) return;

    const originalElement = contentRef.current;
    const clone = originalElement.cloneNode(true) as HTMLElement;

    const mapping: Record<SectionKey, string> = {
      cover: 'section-cover',
      blueprint: 'section-blueprint',
      usage: 'section-usage',
      typography: 'section-typography',
      print: 'section-print',
      ecosystem: 'section-ecosystem',
      palette: 'section-palette'
    };

    Object.entries(mapping).forEach(([key, id]) => {
      if (!selectedSections.includes(key as SectionKey)) {
        const el = clone.querySelector(`#${id}`);
        if (el) {
          // Remove the section and its potential page break
          const pb = el.previousElementSibling;
          if (pb && pb.classList.contains('page-break')) pb.remove();
          el.remove();
        }
      }
    });

    const opt = {
      margin: 0,
      filename: `BRAND_BOOK_${companyName.toUpperCase()}_SELECTED.pdf`,
      image: { type: 'jpeg', quality: 1.0 },
      html2canvas: { scale: 2, useCORS: true, letterRendering: true, scrollY: 0, windowWidth: 1200 },
      jsPDF: { unit: 'mm', format: 'a4', orientation: 'portrait' },
      pagebreak: { mode: ['avoid-all', 'css', 'legacy'] }
    };

    // @ts-ignore
    window.html2pdf().set(opt).from(clone).save();
  };

  return (
    <div className="space-y-20 animate-in fade-in slide-in-from-bottom-4 duration-1000 pb-40">
      <div 
        ref={contentRef} 
        id="branding-export-container" 
        className="bg-white text-indigo-950 overflow-hidden shadow-[0_80px_160px_rgba(0,0,0,0.2)] md:rounded-[5rem] border border-gray-100"
        style={{ width: '100%', maxWidth: '1200px', margin: '0 auto' }}
      >
        {/* COUVERTURE PRESTIGE */}
        <section id="section-cover" className="h-[1000px] flex flex-col justify-center items-center bg-[#050810] text-white p-20 relative overflow-hidden text-center">
          <div className="relative z-10 space-y-12">
            <div className="w-40 h-40 bg-indigo-600 rounded-[3.5rem] flex items-center justify-center mx-auto shadow-2xl rotate-6 border-4 border-white/10">
               <img src={data.logo.faviconImageUrl} className="w-24 h-24 object-contain" alt="Master Symbol" />
            </div>
            <div className="space-y-4">
              <h1 className="text-9xl font-serif font-black tracking-tighter text-white leading-none uppercase">{companyName}</h1>
              <div className="h-1 w-64 bg-indigo-500 mx-auto rounded-full mt-10"></div>
              <p className="text-4xl text-indigo-400 font-light tracking-[0.8em] uppercase mt-6">Directives d'Identité</p>
            </div>
          </div>
          <div className="absolute inset-0 opacity-20 pointer-events-none" style={{ backgroundImage: 'radial-gradient(circle at center, #312e81 0%, transparent 70%)' }}></div>
        </section>

        {/* SECTION 01: BLUEPRINT GÉOMÉTRIQUE (PERFECTION TECHNIQUE) */}
        <div className="page-break"></div>
        <section id="section-blueprint" className="p-24 bg-white space-y-24">
          <div className="flex items-end gap-10 border-b-4 border-indigo-50 pb-16">
            <span className="text-[12rem] font-serif text-indigo-50/80 font-black leading-none select-none">01</span>
            <div className="pb-4">
              <h2 className="text-6xl font-black text-indigo-950 uppercase tracking-tighter">Blueprint Maître</h2>
              <p className="text-indigo-500 font-black tracking-[0.5em] uppercase text-sm mt-4">Anatomie Vectorielle et Rapports de Proportion</p>
            </div>
          </div>

          <div className="grid grid-cols-1 lg:grid-cols-12 gap-24 items-start">
             <div className="lg:col-span-8">
                <div className="bg-[#0b1120] rounded-[4rem] p-24 aspect-square relative flex items-center justify-center overflow-hidden border-[16px] border-[#1e293b] shadow-inner shadow-black/50">
                   <div className="absolute inset-0 opacity-20" style={{ backgroundImage: 'radial-gradient(circle, #38bdf8 0.5px, transparent 0.5px)', backgroundSize: '20px 20px' }}></div>
                   <div className="relative z-10 w-full h-full flex items-center justify-center">
                    {cleanSvgPath && (
                      <svg viewBox="0 0 512 512" className="w-full h-full overflow-visible" xmlns="http://www.w3.org/2000/svg">
                        <circle cx="256" cy="256" r="230" fill="none" stroke="#0ea5e9" strokeWidth="0.5" strokeDasharray="15,10" opacity="0.3" />
                        <circle cx="256" cy="256" r="150" fill="none" stroke="#0ea5e9" strokeWidth="0.5" strokeDasharray="5,5" opacity="0.2" />
                        <line x1="256" y1="0" x2="256" y2="512" stroke="#38bdf8" strokeWidth="0.5" opacity="0.3" />
                        <line x1="0" y1="256" x2="512" y2="256" stroke="#38bdf8" strokeWidth="0.5" opacity="0.3" />
                        <path d="M 50 256 A 206 206 0 0 1 462 256" fill="none" stroke="#0ea5e9" strokeWidth="0.5" strokeDasharray="2,4" opacity="0.2" />
                        <path d={cleanSvgPath} fill="none" stroke="#38bdf8" strokeWidth="2.5" strokeLinejoin="round" strokeLinecap="round" className="drop-shadow-[0_0_15px_rgba(56,189,248,0.4)]" />
                        {/* Vector markers */}
                        <circle cx="256" cy="256" r="4" fill="#38bdf8" />
                        <rect x="252" y="30" width="8" height="8" fill="#38bdf8" opacity="0.5" />
                        <rect x="252" y="474" width="8" height="8" fill="#38bdf8" opacity="0.5" />
                      </svg>
                    )}
                   </div>
                   <div className="absolute top-16 left-16 space-y-2">
                      <div className="flex items-center gap-3"><div className="w-1.5 h-1.5 bg-sky-400 rounded-full animate-pulse"></div><span className="font-mono text-[10px] text-sky-400/80 uppercase">Node_Stability: 100%</span></div>
