    brandingData.styleGuide.mockupImageUrl = await generateImage(mainMockupPrompt, logoUrl);

    setResult(brandingData);
    setTimeout(() => {
      document.getElementById('result-section')?.scrollIntoView({ behavior: 'smooth' });
    }, 300);
  };

