                            <div className="w-16 h-16 border-4 border-white/20 border-t-white rounded-full animate-spin"></div>
                            <p className="text-white/40 text-[11px] font-black uppercase tracking-[0.5em] animate-pulse">Rendu de la bannière dynamique...</p>
                         </div>
                      )}
                      <div className="absolute top-10 left-10 px-6 py-2 bg-indigo-600 text-white text-[10px] font-black uppercase tracking-widest rounded-full shadow-2xl">Broadcast ready</div>
                   </div>
                   <div className="lg:col-span-4 space-y-8">
                       <div className="bg-gray-50 rounded-[4rem] p-12 flex flex-col justify-center space-y-8">
                          <div className="space-y-2">
                             <p className="text-[10px] font-black text-indigo-400 uppercase tracking-widest">Format Social Master</p>
                             <h4 className="text-2xl font-black text-indigo-950 uppercase tracking-tight">Vidéo Promotionnelle</h4>
                          </div>
                          <p className="text-sm font-bold text-slate-500 italic">"Conçue pour captiver l'audience en moins de 3 secondes avec une dynamique cinématique."</p>
                          {data.styleGuide.ecosystem.promoVideoUrl ? (
                             <a href={data.styleGuide.ecosystem.promoVideoUrl} download className="w-full py-5 bg-indigo-950 text-white text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-black transition-all text-center block">Télécharger MP4</a>
                          ) : (
                             <button disabled className="w-full py-5 bg-gray-200 text-gray-400 text-[10px] font-black uppercase tracking-widest rounded-2xl cursor-not-allowed">Traitement...</button>
                          )}
                       </div>

                       {/* AI Copywriting Module */}
                       <div className="bg-indigo-600 rounded-[4rem] p-12 text-white space-y-6">
                           <div className="space-y-2">
                               <p className="text-[10px] font-black text-white/60 uppercase tracking-widest">AI Copywriting</p>
                               <h4 className="text-2xl font-black uppercase tracking-tight">Post de Lancement</h4>
                           </div>

                           {!launchPost ? (
                               <button 
                                 onClick={handleGenerateLaunchPost}
                                 disabled={isGeneratingPost}
                                 className="w-full py-4 bg-white text-indigo-600 text-[10px] font-black uppercase tracking-widest rounded-2xl hover:bg-indigo-50 transition-all disabled:opacity-50 shadow-xl"
                               >
                                  {isGeneratingPost ? "Rédaction..." : "Générer la Stratégie"}
                               </button>
                           ) : (
                               <div className="bg-indigo-800/50 p-6 rounded-3xl relative group/copy border border-indigo-400/30">
                                   <p className="text-xs leading-relaxed font-medium whitespace-pre-wrap max-h-40 overflow-y-auto p-2 scrollbar-thin scrollbar-thumb-indigo-400">
                                       {launchPost}
                                   </p>
                                   <button 
                                      onClick={handleCopyPost}
                                      className="absolute top-4 right-4 p-2 bg-indigo-500 rounded-lg text-white opacity-0 group-hover/copy:opacity-100 transition-all hover:bg-indigo-400 shadow-lg text-[10px] font-bold uppercase tracking-wide"
                                   >
                                      {copySuccess ? "Copié !" : "Copier"}
                                   </button>
                               </div>
                           )}
                       </div>
                   </div>
                </div>
             </div>
          </div>
        </section>

        {/* SECTION 06: NUANCIER TECHNIQUE */}
        <div className="page-break"></div>
        <section id="section-palette" className="p-24 bg-white border-t border-gray-100">
           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-12">
              {data.styleGuide.colors.map((c, i) => (
                <div key={i} className="space-y-6">
                   <div className="h-48 w-full rounded-[3rem] shadow-xl" style={{ backgroundColor: c.hex }}></div>
                   <div className="space-y-2">
                      <h4 className="text-2xl font-black text-indigo-950 uppercase tracking-tighter">{c.name}</h4>
                      <p className="font-mono text-[10px] text-indigo-400 font-bold">{c.hex} • {c.rgb}</p>
                   </div>
                </div>
              ))}
           </div>
        </section>

        <footer className="p-24 bg-indigo-950 text-white flex justify-between items-center text-[10px] font-black uppercase tracking-[0.6em]">
           <p>© 2026 BrandGenius Absolute • Tous Droits Réservés</p>
           <p>Master Bundle Pack v4.6</p>
        </footer>
      </div>

      {/* FLOATING ACTION PANEL */}
      <div className="max-w-5xl mx-auto space-y-12 px-6 print:hidden">
         <div className="glass-dark rounded-[3rem] p-10 border border-white/20">
            <h3 className="text-center text-white text-[12px] font-black uppercase tracking-[0.4em] mb-8">Composition de l'Export PDF</h3>
            <div className="flex flex-wrap justify-center gap-4">
               {[
                 { id: 'cover', label: 'Couverture' },
                 { id: 'blueprint', label: 'Blueprint Logo' },
                 { id: 'usage', label: 'Mode d\'Utilisation' },
                 { id: 'typography', label: 'Typographie' },
                 { id: 'print', label: 'Supports Print' },
                 { id: 'ecosystem', label: 'Écosystème' },
                 { id: 'palette', label: 'Nuancier' }
               ].map((sec) => (
                 <button 
                   key={sec.id}
                   onClick={() => toggleSection(sec.id as SectionKey)}
                   className={`px-8 py-3 rounded-full text-[10px] font-black uppercase tracking-widest transition-all border-2 ${
                     selectedSections.includes(sec.id as SectionKey) 
                       ? 'bg-indigo-600 border-indigo-500 text-white shadow-lg' 
                       : 'bg-white/5 border-white/10 text-white/40 hover:text-white/80'
                   }`}
                 >
                   {sec.label}
                 </button>
               ))}
            </div>
         </div>
         <div className="flex flex-col sm:flex-row gap-8">
            <button 
                onClick={handleDownloadAssets}
                disabled={isZipping}
                className="flex-grow py-10 bg-gradient-to-r from-amber-200 to-yellow-400 text-amber-900 font-black rounded-[3rem] hover:scale-105 transition-all text-xl uppercase tracking-tighter shadow-[0_0_40px_rgba(251,191,36,0.3)] flex items-center justify-center gap-6 disabled:opacity-50"
            >
                {isZipping ? (
                    <>
                        <div className="w-6 h-6 border-4 border-amber-900/30 border-t-amber-900 rounded-full animate-spin"></div>
                        Compression...
                    </>
                ) : (
                    <>
                        <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M4 16v1a3 3 0 003 3h10a3 3 0 003-3v-1m-4-4l-4 4m0 0l-4-4m4 4V4" /></svg>
                        Télécharger le Brand Pack (ZIP)
                    </>
                )}
            </button>
            <button onClick={handleDownloadPDF} disabled={selectedSections.length === 0} className="px-12 py-10 bg-indigo-600 text-white font-black rounded-[3rem] hover:bg-indigo-700 shadow-2xl transition-all text-lg uppercase tracking-tighter flex items-center justify-center gap-4 disabled:opacity-50 border border-white/10">
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" /></svg>
              Export PDF
            </button>
         </div>
      </div>
    </div>
  );
};

export default BrandingResult;
